1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const FIRST_INSURANCE_MULTIPLIER = 1.1;
6	const CURSED_MULTIPLIER = 1.5;
7	const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
8	const ADMIN_FEE = 5;
9	
10	const BASE_PRICE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	};
16	
17	function itemModifierMultiplier(item: Item): number {
18	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
19	  const highEnchantment =
20	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
21	  return cursed * highEnchantment;
22	}
23	
24	export function runScenario(scenario: unknown): unknown {
25	  const { steps } = scenario as Scenario;
26	  const item = steps[0].items[0];
27	  const itemPrice = BASE_PRICE[item.type] * itemModifierMultiplier(item);
28	  const premium = Math.round(itemPrice * FIRST_INSURANCE_MULTIPLIER) + ADMIN_FEE;
29	  return { results: [{ premium }] };
30	}
